# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from sklearn.model_selection import train_test_split
from sklearn.datasets import load_images
from sklearn.model_selection import RandomizedSearchCV
from sklearn.svm import SVC
import joblib
import requests

app = Flask(__name__)

annotators = []

def register_annotator(url):
    annotators.append({"url": url})

def send_image_for_annotation(image, label):
    for annotator in annotators:
        requests.post(annotator["url"], json={"image": image, "label": label})

@app.route('/api/register', methods=['POST'])
def register():
    url = request.json['url']
    register_annotator(url)
    return jsonify({"status": "success"})

def aggregate_labels(images, labels):
    votes = {}
    for label in set(labels):
        votes[label] = 0

    for label, label_votes in zip(labels, votes.values()):
        votes[label] += len([vote for vote in labels if vote == label])

    max_votes = max(votes.values())
    return [label for label, votes in votes.items() if votes == max_votes][0]

def train_model():
    data = load_images()
    X, _ = train_test_split(data.images, test_size=0.2)
    clf = SVC()
    params = {'kernel': ['rbf'], 'gamma': [1, 0.75, 0.5], 'C': [1, 10]}
    random_search = RandomizedSearchCV(estimator=clf, param_distributions=params, n_iter=10)
    random_search.fit(X, data.target)
    joblib.dump(random_search, 'model.pkl')

@app.route('/api/annotate', methods=['POST'])
def annotate():
    images = request.json['images']
    labels = []
    send_image_for_annotation(images[0], None)  # initiate the first vote

    for image in images:
        response = requests.get(request.json['url'])
        response_data = response.json()
        if 'label' in response_data and response_data['label'] is not None:
            labels.append(response_data['label'])

    final_label = aggregate_labels(images, labels)
    return jsonify({"label": final_label})

if __name__ == "__main__":
    app.run(port=5000, debug=True)